/** Bundled asset URLs for imports resolved by the Bun bundler. */
declare module '*.mp4' {
  const src: string;
  export default src;
}

declare module '*.webm' {
  const src: string;
  export default src;
}

declare module '*.webp' {
  const src: string;
  export default src;
}

declare module '*.png' {
  const src: string;
  export default src;
}

declare module '*.jpg' {
  const src: string;
  export default src;
}

declare module '*.jpeg' {
  const src: string;
  export default src;
}

declare module '*.woff2' {
  const src: string;
  export default src;
}

declare module '*.mp3' {
  const src: string;
  export default src;
}

declare module '@public/*/*.mp4' {
  const src: string;
  export default src;
}

declare module '@public/*/*.webp' {
  const src: string;
  export default src;
}

declare module '@public/*/*.png' {
  const src: string;
  export default src;
}

declare module '@public/*/*.mp3' {
  const src: string;
  export default src;
}
